# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace MyProject.Controllers
{
    public class FileUploadController : Controller
    {
        private const string UploadsDirectory = "wwwroot/uploads";

        [HttpPost]
        public IActionResult Upload(IFormFile file)
        {
            if (file == null || file.Length <= 0)
                return BadRequest("No file provided.");

            var allowedMimeTypes = new[] { "image/*", "application/pdf", "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" };
            if (!allowedMimeTypes.Contains(file.ContentType))
                return BadRequest("Invalid file type.");

            var fileName = Path.GetFileName(file.FileName);
            var physicalPath = Path.Combine(UploadsDirectory, fileName);

            using (var stream = new FileStream(physicalPath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok($"File uploaded successfully at: {Url.Content($"~/uploads/{fileName}")}");
        }
    }
}